package com.bankapp.module;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.AsyncTask;
import android.util.Log;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingModule {
    private static final String PREFS_NAME = "banking_prefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    private static final String TAG = "BankingModule";
    
    private Context context;
    private SharedPreferences prefs;
    private ExecutorService executor;
    
    public BankingModule(Context context) {
        this.context = context;
        this.prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        this.executor = Executors.newFixedThreadPool(2);
    }
    
    public BigDecimal getAccountBalance() {
        try {
            String balanceStr = prefs.getString(BALANCE_KEY, "0.00");
            return new BigDecimal(balanceStr).setScale(2, RoundingMode.HALF_UP);
        } catch (NumberFormatException e) {
            Log.e(TAG, "Error parsing balance", e);
            return BigDecimal.ZERO;
        }
    }
    
    public void setAccountBalance(BigDecimal balance) {
        SharedPreferences.Editor editor = prefs.edit();
        editor.putString(BALANCE_KEY, balance.setScale(2, RoundingMode.HALF_UP).toString());
        editor.apply();
    }
    
    public void processTransaction(Transaction transaction) {
        executor.execute(() -> {
            try {
                BigDecimal currentBalance = getAccountBalance();
                BigDecimal newBalance = currentBalance.add(transaction.getAmount());
                
                if (newBalance.compareTo(BigDecimal.ZERO) < 0) {
                    Log.e(TAG, "Insufficient funds for transaction");
                    return;
                }
                
                setAccountBalance(newBalance);
                addToTransactionHistory(transaction);
                
                Log.d(TAG, "Transaction processed successfully: " + transaction.toString());
                
            } catch (Exception e) {
                Log.e(TAG, "Error processing transaction", e);
            }
        });
    }
    
    public List<Transaction> getTransactionHistory() {
        List<Transaction> history = new ArrayList<>();
        String historyStr = prefs.getString(TRANSACTION_HISTORY_KEY, "");
        
        if (!historyStr.isEmpty()) {
            String[] transactions = historyStr.split(";");
            for (String trans : transactions) {
                try {
                    String[] parts = trans.split(",");
                    if (parts.length >= 4) {
                        Transaction transaction = new Transaction(
                            parts[0],
                            new BigDecimal(parts[1]),
                            parts[2],
                            parts[3]
                        );
                        history.add(transaction);
                    }
                } catch (Exception e) {
                    Log.e(TAG, "Error parsing transaction", e);
                }
            }
        }
        
        return history;
    }
    
    private void addToTransactionHistory(Transaction transaction) {
        List<Transaction> history = getTransactionHistory();
        history.add(transaction);
        
        StringBuilder historyStr = new StringBuilder();
        for (int i = 0; i < Math.min(history.size(), 50); i++) {
            Transaction t = history.get(i);
            historyStr.append(t.getId()).append(",")
                      .append(t.getAmount()).append(",")
                      .append(t.getType()).append(",")
                      .append(t.getTimestamp()).append(";");
        }
        
        SharedPreferences.Editor editor = prefs.edit();
        editor.putString(TRANSACTION_HISTORY_KEY, historyStr.toString());
        editor.apply();
    }
    
    public static class Transaction {
        private String id;
        private BigDecimal amount;
        private String type;
        private String timestamp;
        
        public Transaction(String id, BigDecimal amount, String type, String timestamp) {
            this.id = id;
            this.amount = amount;
            this.type = type;
            this.timestamp = timestamp;
        }
        
        public String getId() { return id; }
        public BigDecimal getAmount() { return amount; }
        public String getType() { return type; }
        public String getTimestamp() { return timestamp; }
        
        @Override
        public String toString() {
            return "Transaction{id='" + id + "', amount=" + amount + ", type='" + type + "', timestamp='" + timestamp + "'}";
        }
    }
}